// src/lib/run.ts
async function requireClient(urlOverride) {
  try {
    return await getAuthedClient(urlOverride);
  } catch (err) {
    if (err instanceof NotAuthenticatedError) {
      fail(err.message);
    }
    throw err;
  }
}
function handleError(err) {
  if (err instanceof RecordGoneError) {
    fail(
      `${err.message} \u2014 another editor may have deleted it; check the timeline with \`vw timeline doctor <timelineId>\`.`
    );
  }
  if (err instanceof RecordConflictError) {
    fail(
      `${err.message} \u2014 re-run the command (it re-plans against the fresh state), or pass --force.`
    );
  }
  fail(err instanceof Error ? err.message : String(err));
}

// src/commands/login.ts
function registerAuthCommands(program3) {
  program3.command("login").description("Authenticate with PocketBase and cache the session").option("--url <url>", "PocketBase URL").option(
    "--app-url <url>",
    "webapp origin serving /api-next, for uploads (only when it differs from the PocketBase URL)"
  ).option("--email <email>", "account email").option("--password <password>", "account password").action(async (opts) => {
    try {
      await login(opts);
    } catch (err) {
      handleError(err);
    }
  });
  program3.command("logout").description("Clear the cached session").action(() => logout());
}

