// src/lib/job.ts
async function resolveJobSource(pb, mediaId) {
  const media = await new MediaMutator(pb).getById(mediaId, "UploadRef");
  if (!media) {
    throw new Error(`Media not found: ${mediaId}`);
  }
  const upload = media.expand?.UploadRef ?? (media.UploadRef ? await new UploadMutator(pb).getById(media.UploadRef) : null);
  if (!upload) {
    throw new Error(`Media ${mediaId} has no source upload record.`);
  }
  if (!upload.externalPath) {
    throw new Error(
      `Media ${mediaId} has no stored original file (the upload was never ingested) \u2014 there is nothing for the worker to process.`
    );
  }
  return { media, upload, sourcePath: upload.externalPath };
}
function mediaTypeOf(media) {
  return Array.isArray(media.mediaType) ? media.mediaType[0] : media.mediaType;
}
function requireUserId(pb) {
  const userId = pb.authStore.record?.id;
  if (!userId) {
    throw new Error("User must be authenticated to queue jobs.");
  }
  return userId;
}
function parseLabelJobTypes(value) {
  const parts = value.split(",").map((part) => part.trim()).filter(Boolean);
  if (parts.length === 0) {
    throw new InvalidArgumentError(
      `expected comma-separated label types (${LABEL_JOB_TYPES.join(", ")})`
    );
  }
  const invalid = parts.filter(
    (part) => !LABEL_JOB_TYPES.includes(part)
  );
  if (invalid.length > 0) {
    throw new InvalidArgumentError(
      `invalid label type(s): ${invalid.join(", ")} (expected ${LABEL_JOB_TYPES.join(", ")})`
    );
  }
  return [...new Set(parts)];
}
function labelDetectionConfig(types, confidenceThreshold = 0.5) {
  if (!types || types.length === 0) {
    return { confidenceThreshold, ...ALL_LABEL_DETECTIONS };
  }
  const toggles = Object.fromEntries(
    LABEL_JOB_TYPES.map((type) => [
      LABEL_JOB_TYPE_TO_CONFIG_KEY[type],
      types.includes(type)
    ])
  );
  return { confidenceThreshold, ...toggles };
}
async function createLabelJobTask(pb, opts) {
  const userId = requireUserId(pb);
  const { media, sourcePath } = await resolveJobSource(pb, opts.mediaId);
  if (mediaTypeOf(media) === MediaType.IMAGE) {
    throw new Error(
      `Media ${media.id} is an image \u2014 label detection only runs on media with temporal content (video/audio).`
    );
  }
  const payload = {
    mediaId: media.id,
    fileRef: sourcePath,
    provider: ProcessingProvider.GOOGLE_VIDEO_INTELLIGENCE,
    config: labelDetectionConfig(opts.types, opts.confidence)
  };
  const task = await new TaskMutator(pb).createDetectLabelsTask(
    media.WorkspaceRef,
    userId,
    media.id,
    payload
  );
  return {
    task,
    types: opts.types?.length ? opts.types : [...LABEL_JOB_TYPES]
  };
}
var TRANSCODE_ASSETS = [
  "thumbnail",
  "sprite",
  "filmstrip",
  "proxy",
  "audio"
];
function parseTranscodeAssets(value) {
  const parts = value.split(",").map((part) => part.trim()).filter(Boolean);
  if (parts.length === 0) {
    throw new InvalidArgumentError(
      `expected comma-separated assets (${TRANSCODE_ASSETS.join(", ")})`
    );
  }
  const invalid = parts.filter(
    (part) => !TRANSCODE_ASSETS.includes(part)
  );
  if (invalid.length > 0) {
    throw new InvalidArgumentError(
      `invalid asset(s): ${invalid.join(", ")} (expected ${TRANSCODE_ASSETS.join(", ")})`
    );
  }
  return [...new Set(parts)];
}
function defaultTranscodeAssets(mediaType) {
  switch (mediaType) {
    case MediaType.AUDIO:
      return ["audio"];
    case MediaType.IMAGE:
      return ["thumbnail", "sprite"];
    default:
      return [...TRANSCODE_ASSETS];
  }
}
function transcodePayload(media, uploadId, assets) {
  const isImage = mediaTypeOf(media) === MediaType.IMAGE;
  const payload = {
    uploadId,
    mediaId: media.id,
    provider: ProcessingProvider.FFMPEG
  };
  if (assets.includes("thumbnail")) {
    payload.thumbnail = { timestamp: "midpoint", width: 640, height: 360 };
  }
  if (assets.includes("sprite")) {
    payload.sprite = isImage ? { fps: 1, cols: 1, rows: 1, tileWidth: 320, tileHeight: 180 } : { fps: 1, cols: 10, rows: 10, tileWidth: 320, tileHeight: 180 };
  }
  if (assets.includes("filmstrip")) {
    payload.filmstrip = { cols: 100, rows: 1, tileWidth: 320, tileHeight: 180 };
  }
  if (assets.includes("proxy")) {
    payload.transcode = { enabled: true, codec: "h264", resolution: "720p" };
  }
  if (assets.includes("audio")) {
    payload.audio = { enabled: true, bitrate: "128k" };
  }
  return payload;
}
async function createTranscodeJobTask(pb, opts) {
  const userId = requireUserId(pb);
  const { media, upload } = await resolveJobSource(pb, opts.mediaId);
  const assets = opts.assets?.length ? opts.assets : defaultTranscodeAssets(mediaTypeOf(media));
  const task = await new TaskMutator(pb).createProcessUploadTask(
    media.WorkspaceRef,
    userId,
    upload.id,
    transcodePayload(media, upload.id, assets)
  );
  return { task, assets };
}

// src/commands/job.ts
async function resolveMediaId(pb, opts) {
  if (opts.media) return opts.media;
  const workspaceId = await resolveWorkspaceId(pb, opts.workspace);
  return (await pickMedia(pb, workspaceId)).id;
}
function registerJobCommands(program3) {
  const job = program3.command("job").description(
    "(dev) Manually queue worker jobs for a media item \u2014 re-run transcode or label detection"
  );
  const label = job.command("label").description(
    "(dev) Queue label detection (a detect_labels task) for a media item"
  ).option("-w, --workspace <id>", "workspace id override").option("-m, --media <id>", "source media id").option(
    "-t, --types <types>",
    `comma-separated label types to run: ${LABEL_JOB_TYPES.join(", ")} (default: all; intent only \u2014 the worker's ENABLE_* env flags gate what actually runs)`,
    parseLabelJobTypes
  ).option(
    "--confidence <threshold>",
    "detection confidence threshold, 0\u20131 (default: 0.5)",
    parseUnitInterval
  );
  withJsonOption(label).action(async (opts) => {
    try {
      const pb = await requireClient();
      const mediaId = await resolveMediaId(pb, opts);
      const { task, types } = await createLabelJobTask(pb, {
        mediaId,
        types: opts.types,
        confidence: opts.confidence
      });
      printRecord(
        task,
        [
          `\u2713 Queued detect_labels task ${task.id} for media ${mediaId} (types: ${types.join(", ")})`,
          `  A running worker picks it up; results: vw label list -m ${mediaId}`
        ],
        opts.json
      );
    } catch (err) {
      handleError(err);
    }
  });
  const transcode = job.command("transcode").description(
    "(dev) Queue transcode/preview generation (a process_upload task) for a media item"
  ).option("-w, --workspace <id>", "workspace id override").option("-m, --media <id>", "source media id").option(
    "-a, --assets <assets>",
    `comma-separated assets to regenerate: ${TRANSCODE_ASSETS.join(", ")} (default: all that apply to the media type)`,
    parseTranscodeAssets
  );
  withJsonOption(transcode).action(async (opts) => {
    try {
      const pb = await requireClient();
      const mediaId = await resolveMediaId(pb, opts);
      const { task, assets } = await createTranscodeJobTask(pb, {
        mediaId,
        assets: opts.assets
      });
      printRecord(
        task,
        [
          `\u2713 Queued process_upload task ${task.id} for media ${mediaId} (assets: ${assets.join(", ")})`,
          "  A running worker picks it up; regenerated files replace the current previews when it completes."
        ],
        opts.json
      );
    } catch (err) {
      handleError(err);
    }
  });
}

